	 module fd61(
	input wire d_1,
	input wire clk,
	input wire rst,
	input wire set,
	output reg q_1 
   );

	reg ctrl_set;

	always@(posedge clk or posedge ctrl_set )
	begin
	if(ctrl_set)//违反
			q_1 <= 1'b1;
		else 
			q_1 <= d_1;
	end 

	always@(rst or set )
	begin
		if(set==1)

			ctrl_set <= rst;
	end 

	endmodule

