entity top is
port(
	 data: in std_logic_vector(1 downto 0);
	 sel: in std_logic;
	 Q: inout std_logic
	);
end entity;

architecture rtl of top is
signal temp: std_logic_vector(2 downto 0);
begin
	 temp(0)<=data(0) and temp(2);
	 temp(1)<=temp(0) xor data(1);
	 temp(2)<=data(0) when sel = '0' else temp(1);		//在信号线“temp(2)”检测到组合电路反馈，为避免时序分析时产生反馈循环，不要在组合电路中使用反馈
	 Q <= temp(2);
end;

