process ( A ) is
variable T: std_logic_vector ( 5 downto 1 );
variable W: std_logic_vector ( 15 downto 1 );
variable R: boolean;
variable E: std_logic_vector ( 10 downto 1 );
begin
if ( T = E ) then                          //关系操作符"="右边的10 位与左边5 位宽度不一致，应保持位宽的一致，避免运算错误。
  Q <= "11";
elsif ( ( W <= E ) >= R ) then             //关系操作符"<="右边的10 位与左边15 位宽度不一致，应保持位宽的一致，避免运算错误。
  Q <= "00";
end if;

