library IEEE;
use IEEE.std_logic_1164.all;
entity ENCODER is
  port (
		A : in std_logic_vector(7 downto 0);
		Y : out std_logic_vector(2 downto 0));
end ENCODER;
architecture RTL of ENCODER is
begin
 process (A) begin
  case A is
	when "01111111" => Y <= "000";
	when "10111111" => Y <= "001";
	when "11011111" => Y <= "010";
	when "11101111" => Y <= "011";
	when "11110111" => Y <= "100";
	when "11111011" => Y <= "101";
	when "11111101" => Y <= "110";
	when "11111110" => Y <= "111";
	when others => Y <= "XXX";    //使用‘X’赋值可减小电路面积，但会生成包含未知值的电路，应避免这种给航天器产品造成危险的行为。
   end case;
 end process;

