案例代码：
entity dff is
port (
	clk, reset, data: in std_logic;
	Q: out std_logic
	);
end;
architecture rtl of dff is
signal bf_rst: std_logic;
begin
	bf_rst <= '0' when reset = '1' else
		'1' when clk'event and clk = '1';
process ( clk, bf_rst ) begin                    //非全局复位信号被连接至触发器“Q”的异步复位端。为避免时序分析问题，只有初始复位能被用于异步复位
if bf_rst = '1' then                              //异步控制信号而不是全局复位信号
	Q <= '0';
elsif (clk'event and clk='1') then
	Q <= data;
end if;
end process;
end;

