module fd32(
	input wire [1:0] data,
	input wire sel,
	output reg Q 	
);
 reg temp_1,temp_2,temp_3;

always @(data or sel)
 begin
		temp_1 = data(0) & temp_3;    //不应在组合逻辑电路中使用反馈
		temp_2 =  temp_1 ^ data(1);
		if(sel == 1'b0)
			temp_3 = data(0);
		else
			temp_3 =  temp_2;
		Q = temp_3;	
 end 	
endmodule

