architecture rtl of dff is
signal rst_gen: std_logic;
begin
	rst_gen <= reset_a xor reset_b;
process ( clk, rst_gen ) begin
if rst_gen = '1' then
	Q <= '0';
elsif ( clk'event and clk='1' ) then
	Q <= data;
end if;

