entity mux2x1 is
port (
	IN1, IN2, SEL: in std_logic;
	Q: out std_logic
);
end entity;
architecture basic of mux2x1 is
begin
process ( SEL, IN1, IN2 ) is
begin
if ( SEL = '1' ) then                       //外部端口无法控制时钟系统的选择。必须在测试过程中能够选择单一的时钟系统，否则无法插入扫描
	Q <= IN1;
else
	Q <= IN2;
	end if;
end process;
end architecture;
entity top is
port (
	CLK1, CLK2, CLK3, SEL, D: in std_logic;      //信号“top.CLK1”“top.CLK2是可选的时钟系统
	Q1: out std_logic;
	Q2: out std_logic
	);
end entity;
architecture basic of top is
signal mux_out, D_n, ff_out : std_logic;
begin
	D_n <= not D;
	DFF1 : entity dff port map ( CLK => mux_out, D => D_n, Q => Q1 );
	DFF2 : entity dff port map ( CLK => mux_out, D => D, Q => Q2 );	
	DFF3 : entity dff port map ( CLK => CLK3, D => SEL, Q => ff_out );
	MUX : entity mux2x1 port map ( IN1 => CLK1, IN2 => CLK2, SEL => ff_out, Q=> mux_out );
	end architecture;

