entity sr is
port (
	clk, reset, data_a, data_b: in std_logic;
	Q: out std_logic
 );
end;
architecture rtl of sr is
signal trf12: std_logic;
begin
process ( trf12, reset ) begin
if reset = '1' then
	Q <= '0';
elsif (trf12'event and trf12='1') then
	Q <= data_b;                     //触发器的时钟端“sr.Q”被另一触发器的输出所驱动。时钟树综合工具将无法考虑时钟的平衡
end if;
end process;
process ( clk, reset ) begin
if reset = '1' then
	trf12 <= '0';
elsif (clk'event and clk='1') then
	trf12 <= data_a;              //时钟端由触发器“sr.trf12”所驱动
end if;
end process;
end;

