entity dff is
port (
	  clk, data: in std_logic;
	  q: out std_logic
	  );
end entity;
architecture basic of dff is
begin
process ( clk ) is
begin
 if ( clk'event and clk = '1' ) then
  q <= data;  //实例“top.u_dff_2”的触发器“q”的时钟输入无法直接被外部输入的控制，扫描插入工具会将其排除在外。
 end if;
end process;
end architecture;
entity top is
port (
	  clk, gate, data1, data2: in std_logic;
	  out1: out std_logic;
	  out2: out std_logic
	  );
end entity;
architecture basic of top is
signal clk_gate: std_logic;
begin
 clk_gate <= clk or gate;
   u_dff_1 : entity dff port map ( clk => clk, data => data1, q => out1 );
   u_dff_2 : entity dff port map ( clk =>clk_gate, data => data2, q => out2 );
end architecture;

